import type { AnyBlock, ParsedSession, UserBlock, AgentBlock, ToolBlock } from '@/types';

interface ClaudeCodeEntry {
  type: 'user' | 'assistant' | 'system';
  message: {
    role: string;
    content: string | ContentBlock[];
  };
  timestamp?: string;
  costUSD?: number;
  durationMs?: number;
  inputTokens?: number;
  outputTokens?: number;
}

